#!/usr/bin/env node
/**
 * build-clawhub-bundle.js, Updates the ClawHub bundle's references
 * from canonical skills/shippo/references/.
 *
 * The consolidated SKILL.md at providers/clawhub/skills/shippo/SKILL.md
 * is HAND-CURATED, this script does not regenerate it. Edit it directly
 * when workflow content changes need to land in the ClawHub view.
 *
 * The 4 references that ship with the ClawHub bundle (carrier-guide,
 * csv-format, customs-guide, tool-reference) are kept in lockstep with
 * canonical via this script.
 *
 * Each copied file gets a "DO NOT EDIT" banner injected at the top so
 * humans opening the derived files in an editor see the warning. The
 * references are plain markdown (no YAML frontmatter), so they get an
 * HTML-comment banner; the YAML-comment branch is included for safety
 * in case a future bundled file starts with frontmatter.
 */

const fs = require('fs').promises;
const path = require('path');

const ROOT = path.resolve(__dirname, '..');
const SOURCE_REFS = path.join(ROOT, 'skills/shippo/references');
const BUNDLE_REFS = path.join(ROOT, 'providers/clawhub/skills/shippo/references');

const SCRIPT_NAME = 'build-clawhub-bundle.js';

// Curated subset, only these references ship with the ClawHub bundle.
// Keeps the bundle compact per ClawHub's preference for self-contained skills.
// To add or remove a reference from the ClawHub bundle, edit this list.
const BUNDLED_REFERENCES = [
  'carrier-guide.md',
  'csv-format.md',
  'customs-guide.md',
  'tool-reference.md',
];

function buildYamlBanner(canonicalRelPath) {
  return (
    `# ⚠️  DO NOT EDIT, auto-generated from ${canonicalRelPath} by scripts/${SCRIPT_NAME}\n` +
    `# Edits here will be overwritten on the next sync.\n` +
    `# To change this content, edit the canonical source and re-run the sync script.\n`
  );
}

function buildHtmlBanner(canonicalRelPath) {
  return (
    `<!--\n` +
    `  ⚠️  DO NOT EDIT, auto-generated from ${canonicalRelPath} by scripts/${SCRIPT_NAME}\n` +
    `  Edits here will be overwritten on the next sync.\n` +
    `  To change this content, edit the canonical source and re-run the sync script.\n` +
    `-->\n\n`
  );
}

async function copyWithBanner(src, dest) {
  const content = await fs.readFile(src, 'utf8');
  const canonicalRelPath = path.relative(ROOT, src).split(path.sep).join('/');

  let output;
  if (content.startsWith('---\n')) {
    output = '---\n' + buildYamlBanner(canonicalRelPath) + content.slice(4);
  } else {
    output = buildHtmlBanner(canonicalRelPath) + content;
  }

  await fs.writeFile(dest, output);
}

async function main() {
  await fs.mkdir(BUNDLE_REFS, { recursive: true });

  console.log(`Source: ${SOURCE_REFS}`);
  console.log(`Target: ${BUNDLE_REFS}`);

  for (const ref of BUNDLED_REFERENCES) {
    const src = path.join(SOURCE_REFS, ref);
    const dest = path.join(BUNDLE_REFS, ref);
    await copyWithBanner(src, dest);
    console.log(`  ✓ ${ref}`);
  }

  console.log('\nClawHub bundle references updated.');
  console.log('\nNote: the bundle\'s SKILL.md is generated by scripts/compose-clawhub-digest.js');
  console.log('from the SKILL.md.template + canonical skills/<name>/SKILL.md bodies.');
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});
